from __future__ import annotations

import hashlib
from collections.abc import Mapping
from typing import Annotated, Protocol

import anyio
import httpx
from fastapi import Depends

from app.core.config import REPO_ROOT, Settings, get_settings


class LLMClient(Protocol):
    async def complete(self, *, model: str, system_prompt: str, user_prompt: str) -> str:
        """Return raw model text for a single prompt."""


def prompt_hash(prompt: str) -> str:
    return hashlib.sha256(prompt.encode("utf-8")).hexdigest()


class AnthropicClient:
    """Minimal Anthropic Messages API client used behind the LLMClient protocol."""

    def __init__(
        self,
        *,
        api_key: str,
        timeout: float = 60.0,
        base_url: str = "https://api.anthropic.com/v1/messages",
    ) -> None:
        self._api_key = api_key
        self._timeout = timeout
        self._base_url = base_url

    async def complete(self, *, model: str, system_prompt: str, user_prompt: str) -> str:
        headers = {
            "x-api-key": self._api_key,
            "anthropic-version": "2023-06-01",
            "content-type": "application/json",
        }
        payload = {
            "model": model,
            "max_tokens": 4096,
            "system": [
                {
                    "type": "text",
                    "text": system_prompt,
                    "cache_control": {"type": "ephemeral"},
                }
            ],
            "messages": [{"role": "user", "content": user_prompt}],
        }
        async with httpx.AsyncClient(timeout=self._timeout) as client:
            response = await client.post(self._base_url, headers=headers, json=payload)
            response.raise_for_status()
        data = response.json()
        return "".join(
            block.get("text", "")
            for block in data.get("content", [])
            if isinstance(block, Mapping) and block.get("type") == "text"
        )


class GeminiClient:
    """Minimal Gemini generateContent client used behind the LLMClient protocol."""

    def __init__(
        self,
        *,
        api_key: str,
        timeout: float = 60.0,
        base_url: str = "https://generativelanguage.googleapis.com/v1beta/models",
    ) -> None:
        self._api_key = api_key
        self._timeout = timeout
        self._base_url = base_url

    async def complete(self, *, model: str, system_prompt: str, user_prompt: str) -> str:
        url = f"{self._base_url}/{model}:generateContent"
        payload = {
            "systemInstruction": {"parts": [{"text": system_prompt}]},
            "contents": [{"role": "user", "parts": [{"text": user_prompt}]}],
            "generationConfig": {"maxOutputTokens": 4096, "temperature": 0.2},
        }
        headers = {"content-type": "application/json", "x-goog-api-key": self._api_key}
        delays = [2.0, 5.0, 15.0]
        async with httpx.AsyncClient(timeout=self._timeout) as client:
            for attempt, delay in enumerate([*delays, 0.0]):
                response = await client.post(url, headers=headers, json=payload)
                if response.status_code != httpx.codes.TOO_MANY_REQUESTS or attempt == len(delays):
                    break
                await anyio.sleep(self._retry_after(response, fallback=delay))
        response.raise_for_status()
        data = response.json()
        candidates = data.get("candidates") or []
        if not candidates:
            return ""
        parts = candidates[0].get("content", {}).get("parts", [])
        return "".join(p.get("text", "") for p in parts if isinstance(p, Mapping))

    @staticmethod
    def _retry_after(response: httpx.Response, *, fallback: float) -> float:
        header = response.headers.get("retry-after")
        if header:
            try:
                return float(header)
            except ValueError:
                pass
        try:
            details = response.json().get("error", {}).get("details", [])
            for d in details:
                if d.get("@type", "").endswith("RetryInfo"):
                    raw = d.get("retryDelay", "")
                    if raw.endswith("s"):
                        return float(raw[:-1])
        except (ValueError, AttributeError):
            pass
        return fallback


class FakeLLMClient:
    """Offline LLM test double keyed by (model, prompt_hash(user_prompt))."""

    def __init__(self, responses: Mapping[object, str] | None = None) -> None:
        self.responses = dict(responses or {})
        self.calls: list[dict[str, str]] = []

    def add_response(self, *, model: str, user_prompt: str, response: str) -> None:
        self.responses[(model, prompt_hash(user_prompt))] = response

    async def complete(self, *, model: str, system_prompt: str, user_prompt: str) -> str:
        self.calls.append(
            {
                "model": model,
                "system_hash": prompt_hash(system_prompt),
                "prompt_hash": prompt_hash(user_prompt),
                "user_prompt": user_prompt,
            }
        )
        keys = (
            (model, prompt_hash(user_prompt)),
            (model, user_prompt),
            prompt_hash(user_prompt),
            model,
            "*",
        )
        for key in keys:
            if key in self.responses:
                return self.responses[key]
        return (
            '{"event_id":"","property_id":"LIE-001","summary":"fake empty plan",'
            '"ops":[],"review_items":[]}'
        )


def _system_prompt() -> str:
    return (REPO_ROOT / "schema" / "CLAUDE.md").read_text(encoding="utf-8")


def get_llm_client(
    settings: Annotated[Settings, Depends(get_settings)],
) -> LLMClient:
    match settings.llm_provider:
        case "gemini":
            if settings.gemini_api_key is None:
                return FakeLLMClient()
            return GeminiClient(api_key=settings.gemini_api_key)
        case "anthropic":
            if settings.anthropic_api_key is None:
                return FakeLLMClient()
            return AnthropicClient(api_key=settings.anthropic_api_key)
        case "fake":
            return FakeLLMClient()

        if store.find_entity_by_id(property_id) is None:
            source = self._settings.data_dir / "stammdaten" / "stammdaten.json"
            if source.is_file():
                store.load_from_json(source)
        return store

    def _wiki_chunks_db_path(self) -> Path:
        self._settings.output_dir.mkdir(parents=True, exist_ok=True)
        return self._settings.output_dir / "wiki_chunks.duckdb"


def _list_existing_pages(property_root: Path) -> list[str]:
    if not property_root.is_dir():
        return []
    pages: list[str] = []
    for path in sorted(property_root.rglob("*.md")):
        rel = path.relative_to(property_root)
        if any(part.startswith("_") for part in rel.parts):
            continue
        pages.append(rel.as_posix())
    return pages


def get_supervisor(
    settings: Annotated[Settings, Depends(get_settings)],
    llm: Annotated[LLMClient, Depends(get_llm_client)],
) -> Supervisor:
    return Supervisor(settings=settings, llm=llm)

