export type SimItem = {
  id: string;
  kind: "email" | "invoice" | "bank";
  label: string;
  detail: string;
  source_path: string | null;
  month: string | null;
};

export type SimDay = {
  day: number;
  content_date: string | null;
  emails: SimItem[];
  invoices: SimItem[];
  bank: SimItem[];
};

export type SimTouched = { path: string; content: string };

export type SimIngestResponse = {
  status: string;
  workspace: string;
  wiki_dir: string;
  provider: string;
  fast_model: string;
  smart_model: string;
  duration_ms: number;
  classification: {
    signal: boolean;
    category: string;
    priority: string;
    confidence: number;
  } | null;
  applied_ops: number;
  commit_sha: string | null;
  idempotent: boolean;
  touched: string[];
  files: SimTouched[];
  normalized_text: string | null;
  git_log: string[];
};

export async function fetchIncremental(): Promise<SimDay[]> {
  const r = await fetch(`${base}/sim/incremental`);
  if (!r.ok) throw new Error(`incremental ${r.status}`);
  return r.json();
}

export async function runSimIngest(body: {
  day: number;
  kind: "email" | "invoice" | "bank";
  id: string;
  mode: "isolated" | "live";
  property_id?: string;
}): Promise<SimIngestResponse> {
  const r = await fetch(`${base}/sim/ingest`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!r.ok) {
    const detail = await r.text();
    throw new Error(`sim/ingest ${r.status}: ${detail}`);
  }
  return r.json();
}

export type HumanNotes = { path: string; body: string };

